package cli

import (
	"fmt"
	"os"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
)

func Archive(args []string) {
	if len(args) < 2 {
		println("Usage: tws archive <feature> <branch>")
		return
	}

	internal.RequireTool("git")

	feature := args[0]
	branch := args[1]

	featurePath := internal.FeaturePath(feature)

	// Verify branch is in the stack
	stack, err := internal.LoadStack(featurePath)
	if err != nil || !internal.HasBranch(stack, branch) {
		fmt.Printf("Branch %q not found in feature %q stack\n", branch, feature)
		os.Exit(1)
	}

	path := internal.WorktreePath(feature, branch)

	if _, err := os.Stat(path); os.IsNotExist(err) {
		fmt.Printf("Already archived: %s\n", branch)
		return
	}

	// Remove the worktree
	err = internal.Run("git", "worktree", "remove", path)
	if err != nil {
		// Try force remove if dirty
		err = internal.Run("git", "worktree", "remove", "--force", path)
		if err != nil {
			fmt.Printf("Error removing worktree: %v\n", err)
			os.Exit(1)
		}
	}

	// Prune stale refs
	internal.RunSilent("git", "worktree", "prune")

	fmt.Printf("Archived: %s (branch preserved, restore with: tws new %s %s)\n", branch, feature, branch)
}

package cli

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
)

func List(args []string) {
	wsRoot := internal.TwsRoot()

	if _, err := os.Stat(wsRoot); os.IsNotExist(err) {
		fmt.Println("No workspace found at:", wsRoot)
		return
	}

	entries, err := os.ReadDir(wsRoot)
	if err != nil {
		fmt.Printf("Error reading workspace: %v\n", err)
		os.Exit(1)
	}

	// Filter to feature directories (skip .tws-workspace marker and files)
	var features []string
	for _, e := range entries {
		if !e.IsDir() || e.Name() == ".tws-workspace" {
			continue
		}
		features = append(features, e.Name())
	}

	if len(features) == 0 {
		fmt.Println("No features found. Use 'tws add <feature>' to create one.")
		return
	}

	fmt.Printf("Workspace: %s\n\n", wsRoot)

	for _, feature := range features {
		featurePath := filepath.Join(wsRoot, feature)
		fmt.Printf("%s\n", feature)

		stack, err := internal.LoadStack(featurePath)
		if err == nil && len(stack.Branches) > 0 {
			// Show branches from stack.yaml with base info
			for i, entry := range stack.Branches {
				wtPath := filepath.Join(featurePath, "worktrees", entry.Name)
				status := "active"
				if _, err := os.Stat(wtPath); os.IsNotExist(err) {
					if internal.IsPrunableWorktree(entry.Name) {
						status = "missing"
					} else {
						status = "archived"
					}
				}

				connector := "├──"
				if i == len(stack.Branches)-1 {
					connector = "└──"
				}
				fmt.Printf("  %s %s (base: %s) [%s]\n", connector, entry.Name, entry.Base, status)
			}
		} else {
			// No stack.yaml — list worktree dirs directly
			wtDir := filepath.Join(featurePath, "worktrees")
			wts, err := os.ReadDir(wtDir)
			if err != nil || len(wts) == 0 {
				fmt.Println("  (no branches)")
			} else {
				for i, wt := range wts {
					if !wt.IsDir() {
						continue
					}
					connector := "├──"
					if i == len(wts)-1 {
						connector = "└──"
					}
					fmt.Printf("  %s %s\n", connector, wt.Name())
				}
			}
		}
		fmt.Println()
	}
}

package cli

import (
	"fmt"
	"os"
	"os/exec"
	"strings"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
)

func New(args []string) {
	if len(args) < 2 {
		println("Usage: tws new <feature> <branch> [--base <parent>] [--force]")
		return
	}

	internal.RequireTool("git")

	feature := args[0]
	branch := args[1]
	base := "main"
	force := false

	// Parse flags
	for i := 2; i < len(args); i++ {
		switch args[i] {
		case "--base":
			if i+1 < len(args) {
				base = args[i+1]
				i++
			}
		case "--force", "-f":
			force = true
		}
	}

	featurePath := internal.FeaturePath(feature)
	path := internal.WorktreePath(feature, branch)

	// Ensure parent directory exists
	internal.Must(os.MkdirAll(featurePath, 0755))

	// Create the worktree at the feature-scoped path
	repoRoot, err := internal.MainRepoRoot()
	if err != nil {
		fmt.Println("Error: must be run from inside a git repository")
		os.Exit(1)
	}

	if internal.BranchExists(branch) {
		// Check if it's currently checked out somewhere
		if isCheckedOut(branch) && !force {
			fmt.Printf("Warning: branch %q is already checked out in another worktree.\n", branch)
			fmt.Println("Use --force to check it out anyway.")
			os.Exit(1)
		}

		gitArgs := []string{"worktree", "add"}
		if force {
			gitArgs = append(gitArgs, "--force")
		}
		gitArgs = append(gitArgs, path, branch)
		internal.Must(internal.RunDir(repoRoot, "git", gitArgs...))
	} else {
		// New branch
		internal.Must(internal.RunDir(repoRoot, "git", "worktree", "add", path, "-b", branch))
	}

	// Register branch in stack.yaml (idempotent — skip if already tracked)
	stack, _ := internal.LoadStack(featurePath)
	if !internal.HasBranch(stack, branch) {
		stack.Branches = append(stack.Branches, internal.StackEntry{Name: branch, Base: base})
		internal.Must(internal.SaveStack(featurePath, stack))
	}

	fmt.Printf("Worktree created: %s (base: %s)\n", path, base)
}

// isCheckedOut checks if a branch is currently checked out in any worktree.
func isCheckedOut(branch string) bool {
	out, err := exec.Command("git", "worktree", "list", "--porcelain").Output()
	if err != nil {
		return false
	}
	for _, line := range strings.Split(string(out), "\n") {
		if strings.TrimSpace(line) == "branch refs/heads/"+branch {
			return true
		}
	}
	return false
}

package cli

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/jdbencardinop/tesseraworkspaces/internal"
)

func Sync(args []string) {
	if len(args) < 1 {
		println("Usage: tws sync <feature>")
		return
	}

	internal.RequireTool("git")

	feature := args[0]
	featurePath := internal.FeaturePath(feature)

	internal.Must(internal.Run("git", "fetch"))

	stack, err := internal.LoadStack(featurePath)
	if err != nil {
		syncFallback(featurePath)
		return
	}

	sorted, err := internal.TopoSort(stack)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
		os.Exit(1)
	}

	skipped := make(map[string]bool)
	updatedByRef := make(map[string]bool)

	// Pass 1: rebase active branches with --update-refs
	for _, entry := range sorted {
		if skipped[entry.Name] {
			continue
		}

		path := internal.WorktreePath(feature, entry.Name)
		if _, err := os.Stat(path); os.IsNotExist(err) {
			// Archived — handle in pass 2
			continue
		}

		base := resolveBase(entry.Base)

		err := internal.RunDir(path, "git", "rebase", "--update-refs", base)
		if err != nil {
			fmt.Println(formatSyncStatus(entry.Name, "active", "failed"))
			skipDescendants(stack, entry.Name, skipped)
		} else {
			fmt.Println(formatSyncStatus(entry.Name, "active", "synced"))
			markUpdatedAncestors(stack, entry.Name, featurePath, updatedByRef)
		}
	}

	// Pass 2: handle archived/missing branches not yet updated
	for _, entry := range sorted {
		if skipped[entry.Name] {
			fmt.Println(formatSyncStatus(entry.Name, "skipped", "skipped"))
			continue
		}

		path := internal.WorktreePath(feature, entry.Name)
		if _, err := os.Stat(path); err == nil {
			// Active — already handled in pass 1
			continue
		}

		// Detect missing (stale) vs archived (clean)
		if internal.IsPrunableWorktree(entry.Name) {
			fmt.Printf("  [?] %s (missing — stale worktree ref, run: tws archive %s %s or tws new %s %s)\n",
				entry.Name, feature, entry.Name, feature, entry.Name)
			continue
		}

		if updatedByRef[entry.Name] {
			fmt.Println(formatSyncStatus(entry.Name, "archived", "synced"))
			continue
		}

		// Optimistic rebase without worktree
		base := resolveBase(entry.Base)
		err := internal.RunSilent("git", "rebase", base, entry.Name)
		if err != nil {
			internal.RunSilent("git", "rebase", "--abort")
			fmt.Println(formatSyncStatus(entry.Name, "archived", "conflict"))
			fmt.Printf("    Restore with: tws new %s %s\n", feature, entry.Name)
			skipDescendants(stack, entry.Name, skipped)
		} else {
			fmt.Println(formatSyncStatus(entry.Name, "archived", "synced"))
		}
	}
}

func resolveBase(base string) string {
	if base == "main" {
		return "origin/main"
	}
	return base
}

// markUpdatedAncestors walks up the stack from a branch and marks any archived
// ancestors as updated (they were handled by --update-refs).
func markUpdatedAncestors(stack internal.Stack, branch string, featurePath string, updated map[string]bool) {
	entryMap := make(map[string]internal.StackEntry)
	for _, e := range stack.Branches {
		entryMap[e.Name] = e
	}

	current := branch
	for {
		entry, ok := entryMap[current]
		if !ok {
			break
		}
		parent, ok := entryMap[entry.Base]
		if !ok {
			break
		}
		parentPath := filepath.Join(featurePath, "worktrees", parent.Name)
		if _, err := os.Stat(parentPath); os.IsNotExist(err) {
			updated[parent.Name] = true
		}
		current = parent.Name
	}
}

func skipDescendants(stack internal.Stack, branch string, skipped map[string]bool) {
	descs := internal.Descendants(stack, branch)
	for d := range descs {
		skipped[d] = true
	}
	if len(descs) > 0 {
		fmt.Printf("    Skipping descendants: %s\n", internal.DescendantsList(stack, branch))
	}
}

func formatSyncStatus(name, mode, status string) string {
	symbols := map[string]string{
		"synced":   "+",
		"failed":   "x",
		"skipped":  "-",
		"conflict": "!",
	}
	sym := symbols[status]
	if sym == "" {
		sym = "?"
	}
	return fmt.Sprintf("  [%s] %s (%s)", sym, name, mode)
}

func syncFallback(featurePath string) {
	entries, _ := os.ReadDir(filepath.Join(featurePath, "worktrees"))
	for _, e := range entries {
		if !e.IsDir() {
			continue
		}
		path := filepath.Join(featurePath, "worktrees", e.Name())
		fmt.Printf("Syncing worktree: %s\n", path)
		internal.Must(internal.RunDir(path, "git", "rebase", "--update-refs", "origin/main"))
	}
}

package internal

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

func RequireTool(name string) {
	if _, err := exec.LookPath(name); err != nil {
		fmt.Printf("Error: required tool %q not found in PATH\n", name)
		os.Exit(1)
	}
}

func MainRepoRoot() (string, error) {
	// git-common-dir returns the .git dir of the main repo even from a worktree.
	// In a non-worktree checkout it returns ".git" (relative).
	out, err := exec.Command("git", "rev-parse", "--git-common-dir").Output()
	if err != nil {
		return "", err
	}
	gitDir := strings.TrimSpace(string(out))

	if gitDir == ".git" {
		// Not inside a worktree — fall back to normal detection.
		return RepoRoot()
	}

	// gitDir is absolute (e.g. /path/to/repo/.git), resolve to parent.
	return filepath.Dir(filepath.Clean(gitDir)), nil
}

func RepoRoot() (string, error) {
	out, err := exec.Command("git", "rev-parse", "--show-toplevel").Output()
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(string(out)), nil
}

func BranchExists(branch string) bool {
	err := exec.Command("git", "rev-parse", "--verify", branch).Run()
	return err == nil
}

func Run(name string, args ...string) error {
	cmd := exec.Command(name, args...)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	cmd.Stdin = os.Stdin

	return cmd.Run()
}

func RunDir(dir string, name string, args ...string) error {
	cmd := exec.Command(name, args...)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	cmd.Stdin = os.Stdin
	cmd.Dir = dir

	return cmd.Run()
}

func RunSilent(name string, args ...string) error {
	cmd := exec.Command(name, args...)
	return cmd.Run()
}

// IsPrunableWorktree checks if a branch has a stale (prunable) worktree entry,
// meaning the directory was deleted but git still tracks it.
func IsPrunableWorktree(branch string) bool {
	out, err := exec.Command("git", "worktree", "list", "--porcelain").Output()
	if err != nil {
		return false
	}
	lines := strings.Split(string(out), "\n")
	for i, line := range lines {
		if strings.TrimSpace(line) == "branch refs/heads/"+branch {
			// Check surrounding lines in the same worktree block for "prunable"
			for j := i - 3; j <= i+2 && j < len(lines); j++ {
				if j < 0 {
					continue
				}
				if strings.HasPrefix(lines[j], "prunable") {
					return true
				}
			}
		}
	}
	return false
}

func Must(err error) {
	if err != nil {
		fmt.Println("Error:", err)
		os.Exit(1)
	}
}

package internal

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

type StackEntry struct {
	Name string `yaml:"name"`
	Base string `yaml:"base"`
}

type Stack struct {
	Branches []StackEntry `yaml:"branches"`
}

// HasBranch checks if a branch name already exists in the stack.
func HasBranch(s Stack, name string) bool {
	for _, e := range s.Branches {
		if e.Name == name {
			return true
		}
	}
	return false
}

func StackPath(featurePath string) string {
	return filepath.Join(featurePath, "stack.yaml")
}

func LoadStack(featurePath string) (Stack, error) {
	data, err := os.ReadFile(StackPath(featurePath))
	if err != nil {
		return Stack{}, err
	}
	var s Stack
	if err := yaml.Unmarshal(data, &s); err != nil {
		return Stack{}, err
	}
	return s, nil
}

func SaveStack(featurePath string, s Stack) error {
	data, err := yaml.Marshal(&s)
	if err != nil {
		return err
	}
	return os.WriteFile(StackPath(featurePath), data, 0644)
}

// TopoSort returns branches in dependency order (parents before children).
// Returns an error if the graph contains a cycle.
func TopoSort(s Stack) ([]StackEntry, error) {
	// Build adjacency: base → children
	entryMap := make(map[string]StackEntry)
	children := make(map[string][]string)
	inDegree := make(map[string]int)

	for _, e := range s.Branches {
		entryMap[e.Name] = e
		inDegree[e.Name] = 0
	}

	for _, e := range s.Branches {
		// Only count edges where the base is also a tracked branch
		if _, ok := entryMap[e.Base]; ok {
			children[e.Base] = append(children[e.Base], e.Name)
			inDegree[e.Name]++
		}
	}

	// Kahn's algorithm
	var queue []string
	for name, deg := range inDegree {
		if deg == 0 {
			queue = append(queue, name)
		}
	}

	var sorted []StackEntry
	for len(queue) > 0 {
		name := queue[0]
		queue = queue[1:]
		sorted = append(sorted, entryMap[name])
		for _, child := range children[name] {
			inDegree[child]--
			if inDegree[child] == 0 {
				queue = append(queue, child)
			}
		}
	}

	if len(sorted) != len(s.Branches) {
		return nil, fmt.Errorf("cycle detected in stack.yaml")
	}
	return sorted, nil
}

// Descendants returns all transitive children of the given branch.
func Descendants(s Stack, branch string) map[string]bool {
	children := make(map[string][]string)
	for _, e := range s.Branches {
		children[e.Base] = append(children[e.Base], e.Name)
	}

	result := make(map[string]bool)
	queue := []string{branch}
	for len(queue) > 0 {
		name := queue[0]
		queue = queue[1:]
		for _, child := range children[name] {
			if !result[child] {
				result[child] = true
				queue = append(queue, child)
			}
		}
	}
	return result
}

// PrintTree prints the stack as an indented dependency tree.
func PrintTree(s Stack) {
	children := make(map[string][]string)
	roots := make(map[string]bool)

	for _, e := range s.Branches {
		roots[e.Name] = true
	}
	for _, e := range s.Branches {
		children[e.Base] = append(children[e.Base], e.Name)
		// If base is a tracked branch, this entry is not a root
		for _, other := range s.Branches {
			if other.Name == e.Base {
				delete(roots, e.Name)
				break
			}
		}
	}

	var printNode func(name, prefix string, isLast bool)
	printNode = func(name, prefix string, isLast bool) {
		connector := "├── "
		if isLast {
			connector = "└── "
		}
		fmt.Println(prefix + connector + name)

		childPrefix := prefix
		if isLast {
			childPrefix += "    "
		} else {
			childPrefix += "│   "
		}

		kids := children[name]
		for i, child := range kids {
			printNode(child, childPrefix, i == len(kids)-1)
		}
	}

	// Print from each root's base (usually "main")
	bases := make(map[string]bool)
	for _, e := range s.Branches {
		if roots[e.Name] {
			bases[e.Base] = true
		}
	}

	for base := range bases {
		fmt.Printf("(%s)\n", base)
		kids := children[base]
		for i, child := range kids {
			printNode(child, "", i == len(kids)-1)
		}
	}

	if len(s.Branches) == 0 {
		fmt.Println("No branches tracked. Use 'ts new <feature> <branch>' to add branches.")
	}
}

// FormatBranchStatus formats a branch sync result for display.
func FormatBranchStatus(name, status string) string {
	symbols := map[string]string{
		"synced":  "+",
		"failed":  "x",
		"skipped": "-",
	}
	sym := symbols[status]
	if sym == "" {
		sym = "?"
	}
	return fmt.Sprintf("  [%s] %s", sym, name)
}

// DescendantsList returns Descendants as a sorted display string.
func DescendantsList(s Stack, branch string) string {
	descs := Descendants(s, branch)
	var names []string
	for name := range descs {
		names = append(names, name)
	}
	return strings.Join(names, ", ")
}

package internal

import (
	"os"
	"path/filepath"
	"testing"
)

func TestTopoSort_LinearChain(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "auth-routes", Base: "auth-middleware"},
		{Name: "auth-models", Base: "main"},
		{Name: "auth-middleware", Base: "auth-models"},
	}}

	sorted, err := TopoSort(s)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	// auth-models must come before auth-middleware, which must come before auth-routes
	indexOf := func(name string) int {
		for i, e := range sorted {
			if e.Name == name {
				return i
			}
		}
		return -1
	}

	if indexOf("auth-models") > indexOf("auth-middleware") {
		t.Error("auth-models should come before auth-middleware")
	}
	if indexOf("auth-middleware") > indexOf("auth-routes") {
		t.Error("auth-middleware should come before auth-routes")
	}
}

func TestTopoSort_DAG(t *testing.T) {
	// A→B and A→C (divergent)
	s := Stack{Branches: []StackEntry{
		{Name: "branch-b", Base: "branch-a"},
		{Name: "branch-c", Base: "branch-a"},
		{Name: "branch-a", Base: "main"},
	}}

	sorted, err := TopoSort(s)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}

	if len(sorted) != 3 {
		t.Fatalf("expected 3 entries, got %d", len(sorted))
	}

	// branch-a must come before both b and c
	indexOf := func(name string) int {
		for i, e := range sorted {
			if e.Name == name {
				return i
			}
		}
		return -1
	}

	if indexOf("branch-a") > indexOf("branch-b") {
		t.Error("branch-a should come before branch-b")
	}
	if indexOf("branch-a") > indexOf("branch-c") {
		t.Error("branch-a should come before branch-c")
	}
}

func TestTopoSort_CycleDetection(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "a", Base: "b"},
		{Name: "b", Base: "c"},
		{Name: "c", Base: "a"},
	}}

	_, err := TopoSort(s)
	if err == nil {
		t.Fatal("expected cycle error, got nil")
	}
}

func TestTopoSort_SingleBranch(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "feature", Base: "main"},
	}}

	sorted, err := TopoSort(s)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(sorted) != 1 || sorted[0].Name != "feature" {
		t.Errorf("expected [feature], got %v", sorted)
	}
}

func TestTopoSort_Empty(t *testing.T) {
	s := Stack{}

	sorted, err := TopoSort(s)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(sorted) != 0 {
		t.Errorf("expected empty, got %v", sorted)
	}
}

func TestDescendants(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "a", Base: "main"},
		{Name: "b", Base: "a"},
		{Name: "c", Base: "b"},
		{Name: "d", Base: "a"}, // divergent from b
	}}

	descs := Descendants(s, "a")
	if !descs["b"] || !descs["c"] || !descs["d"] {
		t.Errorf("expected b, c, d as descendants of a, got %v", descs)
	}
	if descs["a"] {
		t.Error("a should not be its own descendant")
	}

	descsB := Descendants(s, "b")
	if !descsB["c"] {
		t.Error("c should be descendant of b")
	}
	if descsB["d"] {
		t.Error("d should not be descendant of b")
	}
}

func TestHasBranch(t *testing.T) {
	s := Stack{Branches: []StackEntry{
		{Name: "auth-models", Base: "main"},
		{Name: "auth-middleware", Base: "auth-models"},
	}}

	if !HasBranch(s, "auth-models") {
		t.Error("should find auth-models")
	}
	if !HasBranch(s, "auth-middleware") {
		t.Error("should find auth-middleware")
	}
	if HasBranch(s, "nonexistent") {
		t.Error("should not find nonexistent")
	}
	if HasBranch(Stack{}, "anything") {
		t.Error("empty stack should not find anything")
	}
}

func TestLoadSaveStack(t *testing.T) {
	tmp := t.TempDir()

	original := Stack{Branches: []StackEntry{
		{Name: "auth-models", Base: "main"},
		{Name: "auth-middleware", Base: "auth-models"},
	}}

	if err := SaveStack(tmp, original); err != nil {
		t.Fatalf("save error: %v", err)
	}

	// Verify file exists
	if _, err := os.Stat(filepath.Join(tmp, "stack.yaml")); err != nil {
		t.Fatalf("stack.yaml not created: %v", err)
	}

	loaded, err := LoadStack(tmp)
	if err != nil {
		t.Fatalf("load error: %v", err)
	}

	if len(loaded.Branches) != 2 {
		t.Fatalf("expected 2 branches, got %d", len(loaded.Branches))
	}
	if loaded.Branches[0].Name != "auth-models" || loaded.Branches[0].Base != "main" {
		t.Errorf("unexpected first entry: %v", loaded.Branches[0])
	}
}

